// Sample of real AI workflow outputs for quality evaluation
const samples = [
  { sample_id: 'S001', workflow: 'Bug Triage Assistant', input: 'Dashboard fails to load when user has more than 200 projects. Affects 12 enterprise accounts. Started after v2.4.1 deployment.', output: { severity: 'P0', rationale: 'Production outage for 12 paying enterprise accounts — dashboard unusable.', engineering_area: 'backend/api', suggested_owner: 'backend engineer' }, criteria: ['correct P0 severity for production outage', 'identifies regression correctly', 'specific engineering area', 'actionable owner suggestion'] },
  { sample_id: 'S002', workflow: 'Survey Response Analyser', input: 'NPS survey with 45 responses: 28 promoters (62%), 9 passives (20%), 8 detractors (18%). Top themes from detractors: slow load times (6), missing bulk actions (5).', output: { nps: 44, primary_theme: 'Performance concerns centred on load times', actionable_insight: 'Optimise dashboard load time for large projects as highest-priority fix', sentiment: 'mixed-positive' }, criteria: ['NPS calculation correct (62-18=44)', 'connects detractor feedback to specific feature', 'actionable insight is specific'] },
  { sample_id: 'S003', workflow: 'JTBD Extractor', input: 'I just want to get to my dashboard and immediately see what everyone is blocked on, without reading through 40 Slack messages.', output: { job: 'See blocked work immediately without reading messages', functional_job: 'Get status visibility', emotional_job: 'Feel in control without communication overhead' }, criteria: ['captures core job accurately', 'separates functional from emotional job', 'job statement is user-voice, not feature-voice'] }
];
return [{ json: { samples, evaluator_model: process.env.AI_MODEL || 'gpt-4o-mini', sampled_at: new Date().toISOString() } }];

const { samples, evaluator_model } = $input.first().json;
const samplesText = samples.map(s => `[${s.sample_id}] ${s.workflow}
Input: ${s.input}
Output: ${JSON.stringify(s.output, null, 2)}
Evaluation criteria: ${s.criteria.join('; ')}`).join('

---

');
const system = `You are a quality evaluator for AI workflow outputs. You score each output on three dimensions (1-5): (1) Accuracy — factually correct and criterion-meeting; (2) Usefulness — actionable and specific for a PM; (3) Format compliance — matches expected structure. You identify specific issues where score is below 4. Return ONLY valid JSON.`;
const user = `Evaluate these ${samples.length} AI workflow output samples:

${samplesText}

Return JSON:
{
  "evaluations": [
    {
      "sample_id": "string",
      "workflow": "string",
      "accuracy_score": 5,
      "usefulness_score": 5,
      "format_score": 5,
      "overall_score": 5.0,
      "issues": ["string"],
      "highlights": ["string"]
    }
  ],
  "quality_summary": "string — overall health of AI output quality across sampled workflows",
  "recommended_actions": ["string"]
}`;
return [{ json: { samples, evaluator_model, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Evaluation Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.evaluations || !Array.isArray(parsed.evaluations)) return [{ json: { _error: true, reason: 'Missing evaluations' } }];
const avg = parsed.evaluations.reduce((s,e) => s + e.overall_score, 0) / parsed.evaluations.length;
const low_quality = parsed.evaluations.filter(e => e.overall_score < 3.5);
return [{ json: { _error: false, result: parsed, meta: { sample_count: upstream.samples.length, avg_overall_score: parseFloat(avg.toFixed(2)), low_quality_count: low_quality.length, generated_at: new Date().toISOString() } } }];

const { result: r, meta: m } = $input.first().json;
const lines = (r.evaluations||[]).map(e => [
  `  [${e.overall_score}/5] ${e.sample_id} — ${e.workflow}`,
  `  Accuracy: ${e.accuracy_score} | Usefulness: ${e.usefulness_score} | Format: ${e.format_score}`,
  e.highlights?.length ? `  ✓ ${e.highlights.join('; ')}` : '',
  e.issues?.length ? `  ⚠ ${e.issues.join('; ')}` : '',
  ''
].filter(Boolean).join('\n')).join('\n');
const report = [
  `AI OUTPUT QUALITY REPORT`,
  `Samples: ${m.sample_count} | Avg score: ${m.avg_overall_score}/5 | Low quality: ${m.low_quality_count} | ${m.generated_at}`,
  ``,
  `SUMMARY: ${r.quality_summary}`,
  ``,
  `EVALUATIONS:`,
  lines,
  `RECOMMENDED ACTIONS:`,
  ...(r.recommended_actions||[]).map(a => `  • ${a}`),
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
